import React from 'react';
import MagnetLines from './Component';

export default function App() {
  return (
    <div className="min-h-screen bg-[#1A1A1B] flex items-center justify-center p-8">
      <div className="relative w-full max-w-2xl aspect-square flex flex-col items-center justify-center p-8 rounded-2xl bg-[#222224] overflow-hidden">
        <div className="absolute top-8 left-8 z-10">
          <h1 className="text-white text-2xl font-medium tracking-tight">Magnet Lines</h1>
          <p className="text-gray-400 text-sm mt-2">Interactive field animation</p>
        </div>
        <MagnetLines rows={12} columns={12} containerSize="70vmin" lineColor="rgba(255, 255, 255, 0.3)" lineWidth="2px" lineHeight="40px" baseAngle={0} />
        <div className="absolute bottom-8 right-8 text-xs text-gray-500 font-mono">MOVE CURSOR</div>
      </div>
    </div>
  );
}
